// frontend/src/pages/Dashboard.jsx
// Campaign Creation Form + Campaign Listing

import { useState, useEffect } from "react";
import { getCrowdfundingContract, toWei, toUnixTimestamp, fromWei, isDeadlinePassed } from "../utils/contracts";

export default function Dashboard({ user, onSelectCampaign }) {
  const [campaigns, setCampaigns] = useState([]);
  const [loading, setLoading] = useState(false);
  const [creating, setCreating] = useState(false);
  const [error, setError] = useState("");
  const [status, setStatus] = useState("");

  // User input form state
  const [form, setForm] = useState({
    title: "", description: "", goal: "", deadline: "",
  });

  // Load data when page loads
  useEffect(() => { 
    loadCampaigns(); 
  }, []);

  async function loadCampaigns() {
    try {
      setLoading(true);
      const contract = await getCrowdfundingContract();
      let fetchedCampaigns = await contract.getAllCampaigns();
      
      // log out to check if data is correct (important for debugging!)
      console.log("Successfully fetched campaigns from blockchain:", fetchedCampaigns);
      
      setCampaigns(fetchedCampaigns);
    } catch (err) {
      console.error(err);
      setError("Failed to load campaigns: " + err.message);
    } finally {
      setLoading(false);
    }
  }

  async function createCampaign() {
    // Basic validation
    if (!form.title || !form.goal || !form.deadline) {
      return setError("Please fill in all required fields la"); // minor casual error message
    }
    
    try {
      setCreating(true);
      setError("");
      setStatus("Creating campaign on blockchain...");
      
      const contract = await getCrowdfundingContract();
      
      console.log("Submitting:", form); // debug print
      
      const tx = await contract.createCampaign(
        form.title,
        form.description,
        toWei(form.goal),
        toUnixTimestamp(form.deadline)
      );
      
      setStatus("Waiting for MetaMask confirmation...");
      await tx.wait(); // wait for the block to be mined
      
      setStatus("Campaign created successfully!");
      // Reset form after success
      setForm({ title: "", description: "", goal: "", deadline: "" });
      
      // refresh the list
      await loadCampaigns();
      
    } catch (err) {
      console.error("Error creating campaign:", err);
      setError("Failed to create campaign: " + err.message);
    } finally {
      setCreating(false);
    }
  }

  // Calculate percentage for the progress bar
  function progressPercent(campaign) {
    const raised = Number(fromWei(campaign.amountRaised));
    const goal   = Number(fromWei(campaign.goal));
    let percent = (raised / goal) * 100;
    return Math.min(percent, 100).toFixed(0); 
  }

  return (
    <div style={{ maxWidth: 900, margin: "0 auto", padding: 24 }}>
      <h2 style={{ fontSize: 20, marginBottom: 20 }}>
        Welcome back, {user.username}
      </h2>

      {/* ── Create Campaign Form Section ── */}
      <div style={cardStyle}>
        <h3 style={{ marginBottom: 16 }}>Start a New Campaign</h3>
        
        <input 
          placeholder="Campaign Title (e.g., TARUMT Blockchain Event Fund) *" 
          value={form.title}
          onChange={e => setForm({ ...form, title: e.target.value })}
          style={inputStyle} 
        />
        
        <textarea 
          placeholder="Briefly describe what the funds are for..." 
          value={form.description}
          onChange={e => setForm({ ...form, description: e.target.value })}
          rows={3} 
          style={{ ...inputStyle, resize: "vertical" }} 
        />
        
        <div style={{ display: "flex", gap: 12 }}>
          <input 
            placeholder="Target Goal (ETH) *" 
            type="number" 
            value={form.goal}
            onChange={e => setForm({ ...form, goal: e.target.value })}
            style={{ ...inputStyle, flex: 1 }} 
          />
          <input 
            type="date" 
            value={form.deadline}
            onChange={e => setForm({ ...form, deadline: e.target.value })}
            style={{ ...inputStyle, flex: 1 }} 
          />
        </div>
        
        <button onClick={createCampaign} disabled={creating} style={btnStyle}>
          {creating ? "Processing..." : "Launch Campaign"}
        </button>
        
        {status && <p style={{ color: "#1D9E75", marginTop: 10, fontWeight: "500" }}>{status}</p>}
        {error  && <p style={{ color: "#D85A30", marginTop: 10, fontWeight: "500" }}>{error}</p>}
      </div>

      {/* ── Campaign List Display ── */}
      <h3 style={{ margin: "24px 0 12px" }}>Active Campaigns</h3>
      {loading && <p>Loading data from Ganache...</p>}
      
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px,1fr))", gap: 16 }}>
        {campaigns.map((c, i) => (
          <div key={i} style={{ ...cardStyle, cursor: "pointer" }}
            onClick={() => onSelectCampaign(c)}>
            <h4 style={{ margin: "0 0 6px" }}>{c.title}</h4>
            <p style={{ fontSize: 13, color: "#666", margin: "0 0 10px" }}>{c.description}</p>
            
            {/* Custom Progress bar */}
            <div style={{ background: "#eee", borderRadius: 99, height: 6, marginBottom: 6 }}>
              <div style={{
                width: progressPercent(c) + "%", background: "#7F77DD",
                height: 6, borderRadius: 99, transition: "width .4s"
              }} />
            </div>
            
            <p style={{ fontSize: 12, color: "#555", fontWeight: "bold" }}>
              {fromWei(c.amountRaised)} / {fromWei(c.goal)} ETH ({progressPercent(c)}%)
            </p>
            <p style={{ fontSize: 12, color: isDeadlinePassed(c.deadline) ? "#D85A30" : "#1D9E75" }}>
              {isDeadlinePassed(c.deadline) ? "Ended" : "Active"} · Deadline: {new Date(Number(c.deadline) * 1000).toLocaleDateString()}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
}

// Basic styling extracted to keep render clean
const cardStyle = { background: "#fff", border: "1px solid #e0e0e0", borderRadius: 16, padding: 24, boxShadow: "0 4px 12px rgba(0,0,0,0.05)" };
const inputStyle = { display: "block", width: "100%", padding: "12px 16px", borderRadius: 10, border: "1px solid #ddd", fontSize: 14, marginBottom: 12, boxSizing: "border-box", backgroundColor: "#f9f9f9" };
const btnStyle = { padding: "12px 24px", background: "#7F77DD", color: "#fff", border: "none", borderRadius: 10, fontSize: 15, cursor: "pointer", fontWeight: "bold", transition: "0.3s" };
